import React from 'react';
import ProductCard from './ProductCard';
import { Product } from '../data/products';

// ProductGrid component: Displays products in a responsive grid layout
// Props: products - array of products to display
// This component arranges ProductCard components in a grid matching Flipkart's layout
interface ProductGridProps {
  products: Product[];
}

const ProductGrid: React.FC<ProductGridProps> = ({ products }) => {
  // If no products, show message
  if (products.length === 0) {
    return (
      <div className="text-center py-12">
        <p className="text-gray-500 text-lg">No products found</p>
      </div>
    );
  }

  return (
    // Grid container with responsive columns
    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
      {/* Map each product to a ProductCard */}
      {products.map((product) => (
        <ProductCard key={product.id} product={product} />
      ))}
    </div>
  );
};

export default ProductGrid;
